import React from 'react';
import Button from './Button/Button';
import s from './Content.module.css'
import Massages from './Massages/Massages';
import Textarea from './textarea/Textarea';

const Content = () => {

let PostData=[
  {id: 1, post:"fuck u", likesCount : 5},
  {id: 1, post:"good luck", likesCount : 23},
  {id: 1, post:"nice try", likesCount : 13},
  {id: 1, post:"maybe", likesCount : 76},
  {id: 1, post:"real talk", likesCount : 29}
]

  return (
    <div>
      <div className={s.text}>
        <div> <h2>Content</h2> </div> 
        <Textarea/>
        <Button/>
        <Massages massage = {PostData[0].post} likesCount = {PostData[0].likesCount}/>
        <Massages massage = {PostData[1].post} likesCount = {PostData[1].likesCount}/>
        <Massages massage = {PostData[2].post} likesCount = {PostData[2].likesCount}/>
        <Massages massage = {PostData[3].post} likesCount = {PostData[3].likesCount}/>
        <Massages massage = {PostData[4].post} likesCount = {PostData[4].likesCount}/>
      </div>
    </div>
  )

}
export default Content;
